class Solution:
    def countIslands(self, grid, k):
        m = len(grid)
        n = len(grid[0])
        # union-find over land cells
        parent = list(range(m * n))
        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x
        def union(a, b):
            ra, rb = find(a), find(b)
            if ra != rb:
                parent[ra] = rb
        for r in range(m):
            for c in range(n):
                if grid[r][c] > 0:
                    if r + 1 < m and grid[r + 1][c] > 0:
                        union(r * n + c, (r + 1) * n + c)
                    if c + 1 < n and grid[r][c + 1] > 0:
                        union(r * n + c, r * n + c + 1)
        totals = {}
        for r in range(m):
            for c in range(n):
                if grid[r][c] > 0:
                    root = find(r * n + c)
                    totals[root] = totals.get(root, 0) + grid[r][c]
        return sum(1 for v in totals.values() if v % k == 0)

