class Solution:
    def countIslands(self, grid, k):
        m = len(grid)
        n = len(grid[0])
        seen = [[False] * n for _ in range(m)]
        ans = 0
        for r in range(m):
            for c in range(n):
                if grid[r][c] > 0 and not seen[r][c]:
                    stack = [(r, c)]
                    seen[r][c] = True
                    total = 0
                    while stack:
                        x, y = stack.pop()
                        total += grid[x][y]
                        for dx, dy in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                            nx, ny = x + dx, y + dy
                            if 0 <= nx < m and 0 <= ny < n and grid[nx][ny] > 0 and not seen[nx][ny]:
                                seen[nx][ny] = True
                                stack.append((nx, ny))
                    if total % k == 0:
                        ans += 1
        return ans

