var countIslands = function(grid, k) {
    const m = grid.length, n = grid[0].length;
    const seen = Array.from({length: m}, () => new Array(n).fill(false));
    let ans = 0;
    const dirs = [[1, 0], [-1, 0], [0, 1], [0, -1]];
    for (let r = 0; r < m; r++) {
        for (let c = 0; c < n; c++) {
            if (grid[r][c] > 0 && !seen[r][c]) {
                const stack = [[r, c]];
                seen[r][c] = true;
                let total = 0;
                while (stack.length) {
                    const [x, y] = stack.pop();
                    total += grid[x][y];
                    for (const [dx, dy] of dirs) {
                        const nx = x + dx, ny = y + dy;
                        if (nx >= 0 && nx < m && ny >= 0 && ny < n && grid[nx][ny] > 0 && !seen[nx][ny]) {
                            seen[nx][ny] = true;
                            stack.push([nx, ny]);
                        }
                    }
                }
                if (total % k === 0) ans++;
            }
        }
    }
    return ans;
};
